    /// <summary>
    /// Control to run the CreatingMonthEndInventoryTable
    /// </summary>
    /// <param name = "_args">Args</param>
    public static void main(Args _args)
    {
        SysOperationServiceController controller = new KJP_SM_DataOutputForPSIReportIntegrationController(
            classStr(KJP_SM_DataOutputForPSIReportIntegrationService),
            methodStr(KJP_SM_DataOutputForPSIReportIntegrationService, runDataOutputForPSIReportIntegrationController),
            SysOperationExecutionMode::Synchronous);

        KJP_SM_DataOutputForPSIReportIntegrationController::runMain(_args, controller);
    }

/// <summary>
/// Control to run the CreatingMonthEndInventoryTableBatchDialog
/// </summary>
/// <param name = "_args">Args</param>
/// <param name = "_controller">SysOperationServiceController</param>
private static void runMain(Args _args, SysOperationServiceController _controller)
{
    _controller.parmDialogCaption("@KJP:KJP103774");
    _controller.parmArgs(_args);
    _controller.parmLoadFromSysLastValue(true);
    _controller.showBatchTab(true);
    _controller.startOperation();
}
